export default function ProjectLinks({ projectId }: ProjectLinksProps) {
  const t = useTranslations("projects");

  const githubLink = t("items." + projectId + ".links.github");
  const liveLink = t("items." + projectId + ".links.live");

  const githubFallback = "projects.items." + projectId + ".links.github";
  const liveFallback = "projects.items." + projectId + ".links.live";

  const isGithubValide = githubLink && githubLink !== githubFallback && githubLink !== "null" && githubLink !== "";
  const isLiveValide = liveLink && liveLink !== liveFallback && liveLink !== "null" && liveLink !== "";

  if (!isGithubValide && !isLiveValide) return null;

  return (
    <LinksContainer>
      {isGithubValide && <LinkButton href={githubLink} target="_blank">Code</LinkButton>}
      {isLiveValide && <LinkButton href={liveLink} target="_blank" className="live-btn">Live Demo</LinkButton>}
    </LinksContainer>
  );
}

'use client';

import useSWR from 'swr';
import { toast } from 'react-toastify';

interface CalculationResult {
  competitionId: string;
  competitionName: string;
  calculatedPoints: number;
  status: string;
}

const fetcher = (url: string) => fetch(url).then((res) => {
  if (!res.ok) throw new Error('Kalkulation fejlede');
  return res.json();
});

export function useCompetitionData(competitionId: string) {
  const { data, error, isLoading } = useSWR<CalculationResult>(
    competitionId ? `/api/competitions/${competitionId}/calculate` : null,
    fetcher,
    {
      onSuccess: () => toast.success('Scenarieberegning opdateret med succes!'),
      onError: () => toast.error('Fejl under automatisk pointberegning.'),
      revalidateOnFocus: false
    }
  );

  return {
    result: data,
    isError: error,
    isLoading
  };
}

// Next.js API-route til administration af dyr i Zoo-Manager
import type { NextApiRequest, NextApiResponse } from 'next';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export default async function handler(
  req: NextApiRequest,
  res: NextApiResponse
) {
  const { method } = req;

  switch (method) {
    case 'GET':
      try {
        // Hent alle dyr inklusive deres farvevarianter fra MariaDB
        const animals = await prisma.animal.findMany({
          include: { variants: true },
          orderBy: { name: 'asc' },
        });
        return res.status(200).json(animals);
      } catch (error) {
        return res.status(500).json({ error: 'Failed to fetch animal data' });
      }

    case 'POST':
      try {
        const { name, enclosureId, species } = req.body;
        if (!name || !enclosureId) {
          return res.status(400).json({ error: 'Missing required fields' });
        }

        const newAnimal = await prisma.animal.create({
          data: { name, enclosureId, species },
        });
        return res.status(201).json(newAnimal);
      } catch (error) {
        return res.status(500).json({ error: 'Could not create animal entry' });
      }

    default:
      res.setHeader('Allow', ['GET', 'POST']);
      return res.status(405).end(`Method ${method} Not Allowed`);
  }
}

