package teccon.emobility.charging;

import jakarta.inject.Inject;
import jakarta.ws.rs.*;
import jakarta.ws.rs.core.MediaType;
import jakarta.ws.rs.core.Response;
import org.eclipse.microprofile.reactive.messaging.Channel;
import org.eclipse.microprofile.reactive.messaging.Emitter;

@Path("/api/v1/charging-stations")
@Produces(MediaType.APPLICATION_JSON)
@Consumes(MediaType.APPLICATION_JSON)
public class ChargingStationResource {

    @Inject
    @Channel("station-commands")
    Emitter<String> commandEmitter;

    /**
     * Sender en fjernstartskommando til en specifik ladestander via Apache Kafka.
     */
    @POST
    @Path("/{id}/start")
    public Response remoteStartTransaction(@PathParam("id") String stationId, ChargingCommandDTO commandDTO) {
        if (commandDTO == null || commandDTO.getUserId() == null) {
            return Response.status(Response.Status.BAD_REQUEST)
                           .entity("Invalid command payload.").build();
        }

        // Klargør event-payload til Kafka og send asynkront
        String payload = String.format("{\"stationId\":\"%s\",\"action\":\"START\",\"user\":\"%s\"}", 
                                       stationId, commandDTO.getUserId());
        commandEmitter.send(payload);

        return Response.status(Response.Status.ACCEPTED)
                       .entity(new CommandResponseDTO(stationId, "START_REQUESTED")).build();
    }
}

// Spring Boot REST-controller til tilgængelig dokumentgenerering
package teccon.ba.infosysbub.pdf;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/v1/documents")
public class PdfGenerationController {

    @Autowired
    private AccessiblePdfService pdfService;

    /**
     * Genererer en tilgængelig PDF (PDF/UA-konform) baseret på de indsendte ansøgningsdata.
     */
    @POST
    @Path("/generate-avgs")
    public ResponseEntity<byte[]> generateAvgsPdf(@RequestBody AvgsDocumentDTO documentDTO) {
        // Kald til tjenesten for at generere den tilgængelige dokument-bytestrøm
        byte[] pdfContent = pdfService.createAccessibleDocument(documentDTO);

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_PDF);
        headers.setContentDispositionFormData("attachment", "avgs-bescheinigung.pdf");
        headers.setCacheControl("must-revalidate, post-check=0, pre-check=0");

        return new ResponseEntity<>(pdfContent, headers, HttpStatus.OK);
    }
}

