package com.edict.marketing.bonus;

import javax.inject.Inject;
import javax.ws.rs.*;
import javax.ws.rs.core.MediaType;
import javax.ws.rs.core.Response;

@Path("/api/v1/bonuses")
@Produces(MediaType.APPLICATION_JSON)
@Consumes(MediaType.APPLICATION_JSON)
public class BonusResource {

    @Inject
    BonusCampaignService bonusService;

    /**
     * Opretter en ny gratis spilkampagne konfigureret i Angular-frontend-administrationspanelet.
     */
    @POST
    public Response createBonusCampaign(BonusCampaignDTO campaignDTO) {
        if (campaignDTO.getAmountOfFreespins() <= 0) {
            return Response.status(Response.Status.BAD_REQUEST)
                           .entity("Freespins quantity must be greater than zero.").build();
        }

        BonusCampaignCreatedResponse response = bonusService.processAndSaveCampaign(campaignDTO);
        return Response.status(Response.Status.CREATED).entity(response).build();
    }
}

